import React from "react";

function AddProduct() {
  return (
    <div style={{ padding: "30px" }}>
      <h1>Add Product</h1>

      <input
        type="text"
        placeholder="Product Title"
        style={{
          display: "block",
          margin: "10px 0",
          padding: "10px",
        }}
      />

      <textarea
        placeholder="Product Description"
        style={{
          display: "block",
          margin: "10px 0",
          padding: "10px",
        }}
      />

      <input
        type="number"
        placeholder="Price"
        style={{
          display: "block",
          margin: "10px 0",
          padding: "10px",
        }}
      />

      <button>Add Product</button>
    </div>
  );
}

export default AddProduct;
